813 /// Analyze XOR instruction to extract disjoint constant bits for address
814 /// folding
815 ///
816 /// This function identifies bits in an XOR constant operand that are disjoint
817 /// from the base operand's known set bits. For these disjoint bits, XOR behaves
818 /// identically to addition, allowing us to extract them as constant offsets
819 /// that can be folded into addressing modes.
820 ///
821 /// Transformation: `Base ^ Const` becomes `(Base ^ NonDisjointBits) +
822 /// DisjointBits` where DisjointBits = Const & KnownZeros(Base)
823 ///
824 /// Example with ptr having known-zero low bit:
825 ///   Original: `xor %ptr, 3`    ; 3 = 0b11
826 ///   Analysis: DisjointBits = 3 & KnownZeros(%ptr) = 0b11 & 0b01 = 0b01
827 ///   Result:   `(xor %ptr, 2) + 1` where 1 can be folded into address mode
828 ///
829 /// \param XorInst The XOR binary operator to analyze
830 /// \return APInt containing the disjoint bits that can be extracted as offset,
831 ///         or zero if no disjoint bits exist
832 std::pair<APInt, APInt>
833 ConstantOffsetExtractor::extractDisjointBitsFromXor(BinaryOperator *XorInst) {
834   assert(XorInst && XorInst->getOpcode() == Instruction::Xor &&
835          "Expected XOR instruction");
836 
837   const unsigned BitWidth = XorInst->getType()->getScalarSizeInBits();
838   Value *BaseOperand;
839   ConstantInt *XorConstant;
840 
841   // Match pattern: xor BaseOperand, Constant.
842   if (!match(XorInst, m_Xor(m_Value(BaseOperand), m_ConstantInt(XorConstant))))
843     return {APInt::getZero(BitWidth), APInt::getZero(BitWidth)};
844 
845   // Compute known bits for the base operand.
846   const SimplifyQuery SQ(DL);
847   const KnownBits BaseKnownBits = computeKnownBits(BaseOperand, SQ);
848   const APInt &ConstantValue = XorConstant->getValue();
849 
850   // Identify disjoint bits: constant bits that are known zero in base.
851   const APInt DisjointBits = ConstantValue & BaseKnownBits.Zero;
852 
853   // Early exit if no disjoint bits found.
854   if (DisjointBits.isZero())
855     return {APInt::getZero(BitWidth), APInt::getZero(BitWidth)};
856 
857   // Compute the remaining non-disjoint bits that stay in the XOR.
858   const APInt NonDisjointBits = ConstantValue & ~DisjointBits;
859 
860   // FIXME: Enhance XOR constant extraction to handle nested binary operations.
861   // Currently we only extract disjoint bits from the immediate XOR constant,
862   // but we could recursively process cases like:
863   //   xor (add %base, C1), C2  ->  add %base, (C1 ^ disjoint_bits(C2))
864   // This requires careful analysis to ensure the transformation preserves
865   // semantics, particularly around sign extension and overflow behavior.
866 
867   // Add the non-disjoint constant to the user chain for later transformation
868   // This will replace the original constant in the XOR with the new
869   // constant.
870   UserChain.push_back(ConstantInt::get(XorInst->getType(), NonDisjointBits));
871   return {DisjointBits, NonDisjointBits};
872 }
