874 /// A helper function to check if reassociating through an entry in the user
875 /// chain would invalidate the GEP's nuw flag.
876 static bool allowsPreservingNUW(const User *U) {
877   if (const BinaryOperator *BO = dyn_cast<BinaryOperator>(U)) {
878     // Binary operations need to be effectively add nuw.
879     auto Opcode = BO->getOpcode();
880     if (Opcode == BinaryOperator::Or) {
881       // Ors are only considered here if they are disjoint. The addition that
882       // they represent in this case is NUW.
883       assert(cast<PossiblyDisjointInst>(BO)->isDisjoint());
884       return true;
885     }
886     return Opcode == BinaryOperator::Add && BO->hasNoUnsignedWrap();
887   }
