889   // Among the possible CastInsts, only trunc without nuw is a problem: If it
890   // is distributed through an add nuw, wrapping may occur:
891   // "add nuw trunc(a), trunc(b)" is more poisonous than "trunc(add nuw a, b)"
892   if (const TruncInst *TI = dyn_cast<TruncInst>(U))
893     return TI->hasNoUnsignedWrap();
894   assert((isa<CastInst>(U) || isa<ConstantInt>(U)) && "Unexpected User.");
