644     }
645 
646     Instruction *Cast = I->clone();
647     Cast->setOperand(0, Current);
648     // In ConstantOffsetExtractor::find we do not analyze nuw/nsw for trunc, so
649     // we assume that it is ok to redistribute trunc over add/sub/or. But for
